// CSD_RATIONALE_BEGIN
// This strategy uses constrained decoding to generate FOL formulas for FOLIO logical reasoning.
// It enforces a strict FOL grammar with quantifiers, predicates, and logical connectives.
// The strategy alternates between unconstrained and constrained steps to maintain grammar integrity.
// Constrained steps ensure the prefix is always complete, while unconstrained steps allow free text.
// The strategy uses a step counter to decide when to switch to constrained steps.
// CSD_RATIONALE_END

var helpers := new CSDHelpers();
var stepsLeft := maxSteps;
var stepCounter := 0;

generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  CSDHelpers.RollbackPreservesTokenInvariant(lm, parser, generated);

  if (stepCounter % 2 == 0) // Even steps: unconstrained
  {
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
  }
  else // Odd steps: constrained
  {
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
  }

  generated := generated + [next];
  stepsLeft := newSteps;

  stepCounter := stepCounter + 1;
}

